        val userQuery = (json \ "query").extract[String]

        try {
          val result: DataFrame = spark.sql(userQuery)
          response.setContentType("application/json")
          response.setStatus(HttpServletResponse.SC_OK)
          response.getWriter.println(compact(render(("data" -> result.collect()) ~ ("status" -> "success"))))
